// // This module decrements a 4-bit binary counter on each positive edge of the clock signal and resets to all ones when the reset signal is asserted.
module rc_oscillator_counter(  
    input wire clk,  
    input wire rst,  
    output reg [3:0] count  
);  
    always @(posedge clk or posedge rst) begin  
        if (rst)  
            count <= 4'b0000;  
        else  
            count <= count + 1;  
    end  
endmodule
